@Test public void testFold() throws Exception { Assert.assertEquals("this is
 a test", MimeUtil.fold("this is a test", 68)); Assert.assertEquals("this is
 a test", MimeUtil.fold("this is a test", 69)); Assert.assertEquals("this
 is a test", MimeUtil.fold("this is a test", 70)); Assert.assertEquals("this 
 is a test", MimeUtil.fold( "this is a test", 70)); }

