@Test public void testRemoveTrailingAndLeading() { StringTrimmer stringTrimmer = new StringTrimmer(); assertEquals(expected, stringTrimmer.removeTrailingAndLeading(expected)); assertEquals(expected, stringTrimmer.removeTrailingAndLeading(" abc")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading(" abc ")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading(" abc ")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading(" abc ")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading(" abc ")); assertEquals("ab c", stringTrimmer.removeTrailingAndLeading(" ab c")); assertEquals("a b c", stringTrimmer.removeTrailingAndLeading(" a b c ")); assertEquals("", stringTrimmer.removeTrailingAndLeading("aaa", "a")); assertEquals("", stringTrimmer.removeTrailingAndLeading("	", "	")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading("	" + expected, "	")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading(expected + "	", "	")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading('	' + expected, "	")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading('	' + expected, '	' + "")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading('	' + expected + '	' + '	', "	")); assertEquals("abc ", stringTrimmer.removeTrailingAndLeading("	" + "abc ", "	")); assertEquals("a" + "	" + "bc", stringTrimmer.removeTrailingAndLeading("	" + "a" + "	" + "bc", "	")); assertEquals("	" + expected, stringTrimmer.removeTrailingAndLeading("	" + "abc ")); assertEquals(expected, ("	" + "abc ").trim()); assertEquals(expected, stringTrimmer.removeTrailingAndLeading("
" + expected, "
")); assertEquals("abc ", stringTrimmer.removeTrailingAndLeading("
" + "abc ", "
")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading(expected, "")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading("" + expected, "")); assertEquals(expected, stringTrimmer.removeTrailingAndLeading("" + expected + "", "")); assertEquals("abc ", stringTrimmer.removeTrailingAndLeading("" + "abc ", "")); assertEquals("abc ", stringTrimmer.removeTrailingAndLeading("" + "abc " + "", "")); assertEquals("bc", stringTrimmer.removeTrailingAndLeading(" abc", " a")); assertEquals(" a", stringTrimmer.removeTrailingAndLeading(" abc", "bc")); assertEquals("ab", stringTrimmer.removeTrailingAndLeading("cabc", "c")); assertEquals("𠀀𠀁b", stringTrimmer.removeTrailingAndLeading("a𠀀𠀁ba", "a")); assertEquals("a𠀁b", stringTrimmer.removeTrailingAndLeading("𠀀a𠀁b", "𠀀")); }

