public static String normalizeXmlString(String xml) { log.debug("XML from start:
{}", xml); Document doc = createDocument(xml); doc.setXmlStandalone(true); xml = getXml(doc, false, 0); log.debug("XML after removing whitespace:
{}", xml); doc = createDocument(xml); doc.setXmlStandalone(true); xml = getXml(doc, true, 2); log.debug("XML fully normalized:
{}", xml); return xml; }
